<script>
export default {
	name: 'ProductButton',
	data() {
		return {
			label: 'Product',
		}
	},
	components: {},
	computed: {
		isClicked() {
			return this.$store.getters.team === this.label
		},
	},
	methods: {
		buttonClick() {
			if (this.isClicked) {
				this.$store.dispatch('changeTeam', '')
			} else {
				this.$store.dispatch('changeTeam', this.label)
			}
		},
	},
}
</script>

